package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlin.test.Test
import kotlin.test.assertEquals

class ParsingRegressionTest {

    @Test
    fun localDateParsesExpandedYearWithManyLeadingZeros() {
        val text = "+00000000000002022-07-16"
        val expected = LocalDate(2022, 7, 16)

        assertEquals(expected, LocalDate.parse(text))
        assertEquals(expected, LocalDate.Formats.ISO.parse(text))
    }

    @Test
    fun localDateTimeParsesExpandedYearWithManyLeadingZeros() {
        val text = "+00000000000002022-07-16T01:02:03"
        val expected = LocalDateTime(2022, 7, 16, 1, 2, 3)

        assertEquals(expected, LocalDateTime.parse(text))
        assertEquals(expected, LocalDateTime.Formats.ISO.parse(text))
    }

    @Test
    fun dateTimePeriodDoesNotParseBareP() {
        assertInvalidFormat { DateTimePeriod.parse("P") }
        assertInvalidFormat { DateTimePeriod.parse("+P") }
        assertInvalidFormat { DateTimePeriod.parse("-P") }

        assertInvalidFormat { DatePeriod.parse("P") }
        assertInvalidFormat { DatePeriod.parse("+P") }
        assertInvalidFormat { DatePeriod.parse("-P") }
    }
}
"}

